INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('english', 'WAEC', 'Abdul''s contribution at the meeting was seen by many as invaluable but the chairman said it was _________.', 'insincere', 'useless', 'impossible', 'preposterous', NULL, 'B', 'Useless: This fits the context because it directly contrasts with "invaluable." If something is invaluable, it means it''s very valuable. Saying it''s useless is a direct negation.', 2024), 
('english', 'WAEC', 'The boy may be culpable but his brother is surely _________.', 'innocent', 'ignorant', 'accountable', 'honest', NULL, 'A', 'Innocent: This is the best choice because "culpable" means guilty, and "innocent" is the direct opposite.', 2024), 
('english', 'WAEC', 'Our class teacher used to be rigid in his opinions but he is now _________ of other people''s views.', 'wary', 'critical', 'apprise', 'tolerant', NULL, 'D', 'Tolerant: This means accepting and open-minded, which is the opposite of being rigid.', 2024), 
('english', 'WAEC', 'Some workers were quite affable at the meeting but their leader was rather _________.', 'guarded', 'caution', 'suspicious', 'antagonistic', NULL, 'D', 'Antagonistic: This means hostile, which is the opposite of being friendly (affable).', 2024), 
('english', 'WAEC', 'The driver believed he would be castigated by all the passengers but he was _________.', 'encouraged', 'exonerated', 'commended', 'released', NULL, 'C', 'Commended: This means praised, which is the opposite of castigated (scolded).', 2024), 
('english', 'WAEC', 'The manager was eulogized for his speech while his assistant was _________.', 'discourage', 'criticized', 'appraised', 'denounced', NULL, 'B', 'Criticized: "Eulogized" means praised formally, especially at a funeral. The opposite would be "criticized."', 2024), 
('english', 'WAEC', 'Some people are generous towards strangers, while others are _________ towards them.', 'indifferent', 'sympathetic', 'thetic', 'nasty', NULL, 'A', '"Generous" means willing to give more than is usual or expected. The opposite would be "indifferent" — not caring or showing concern.', 2024), 
('english', 'WAEC', 'The baby who had all long been calm suddenly became _________.', 'restless', 'angry', 'cheerful', 'hungry', NULL, 'A', '"Calm" means not showing any strong emotions. The opposite is "restless" — unable to stay still.', 2024), 
('english', 'WAEC', 'While Ade is _________, his wife is quite self-effacing.', 'aggressive', 'lousy', 'conceited', 'unfriendly', NULL, 'C', '"Self-effacing" means not claiming attention for oneself, retiring and modest. The opposite would be "conceited."', 2024), 
('english', 'WAEC', 'Bakary is a prudent husband while Musa is _________.', 'mean', 'extravagant', 'mindless', 'thoughtful', NULL, 'B', '"Prudent" means careful and wise, especially in financial matters. The opposite is "extravagant."', 2024), 
('english', 'WAEC', 'The incumbent chairman won the election by a _________ of twenty votes.', 'surplus', 'consensus', 'space', 'margin', NULL, 'D', '"Margin" is the correct word — the difference by which one candidate won over another in an election.', 2024), 
('english', 'WAEC', 'Since all items on the agenda had been discussed, the meeting was _________.', 'dismissed', 'suspended', 'adjourned', 'dissolved', NULL, 'C', '"Adjourned" is the appropriate word meaning the meeting was formally brought to an end or postponed to a later time.', 2024), 
('english', 'WAEC', 'The police explained that all the aggrieved persons should seek _________ in the court of law.', 'redress', 'litigation', 'address', 'restoration', NULL, 'A', '"Redress" means remedy or compensation for a wrong or grievance — the appropriate legal term here.', 2024), 
('english', 'WAEC', 'Our principle has a large _________ of cows.', 'gang', 'herd', 'skein', 'flock', NULL, 'B', '"Herd" is the collective noun for cows. A gang is for criminals, a skein is for geese in flight, a flock is for birds or sheep.', 2024), 
('english', 'WAEC', 'The first storey building in Nigeria stands as a historic _________.', 'effigy', 'artefact', 'monument', 'edifice', NULL, 'C', '"Monument" refers to a structure built to commemorate a person or event. A historic monument is something preserved because of its historical significance.', 2024), 
('english', 'WAEC', 'I returned from the vacation refreshed and _________.', 'rejuvenated', 'revived', 'reloaded', 'remodeled', NULL, 'A', '"Rejuvenated" means to feel young and energetic again — the most appropriate word after "refreshed."', 2024), 
('english', 'WAEC', 'She was advised to see a _________ because she had an unusual skin disease.', 'cardiologist', 'dermatologist', 'gynaecologist', 'ophthalmologist', NULL, 'B', '"Dermatologist" is a doctor who specialises in skin conditions — the correct register for treating skin diseases.', 2024), 
('english', 'WAEC', 'The doctor''s _________ was that the patient was suffering from cancer.', 'prediction', 'prescription', 'diagnosis', 'analysis', NULL, 'C', '"Diagnosis" is the appropriate word — it refers to the identification of a disease from its symptoms.', 2024), 
('english', 'WAEC', 'Tom''s father gave him a valuable gift as an _________ to make him work harder in school.', 'incentive', 'attraction', 'interest', 'offer', NULL, 'A', '"Incentive" means something that motivates or encourages someone to do something — the correct word here.', 2024), 
('english', 'WAEC', 'We have not yet heard the weather _________.', 'forecast', 'broadcast', 'prediction', 'announcement', NULL, 'A', '"Forecast" is the specific word used for weather — a weather forecast is a prediction of weather conditions.', 2024), 
('english', 'WAEC', 'Ojo was cautioned not to jangle the old man''s nerve. This means that Ojo was cautioned not to:', 'annoy the old man', 'harass the old man', 'disturb the old man', 'tease the old man', NULL, 'A', '"Jangle someone''s nerves" means to irritate or annoy them — option A best captures this meaning.', 2024), 
('english', 'WAEC', 'Amina was completely swept off her feet the first time she met Gabriel. This means that she:', 'fell deeply in love', 'was pleasantly surprised', 'trusted him completely', 'became utterly confused', NULL, 'A', '"Swept off her feet" means to fall deeply in love suddenly and completely.', 2024), 
('english', 'WAEC', 'His response showed that he kept abreast of events in the country. This means that he was:', 'mindful of events', 'involved in events', 'well-informed about events', 'curious about events', NULL, 'C', '"Keep abreast of" means to stay informed or up to date with events or developments.', 2024), 
('english', 'WAEC', 'Our school is the last but one on that road. This means that our school is:', 'the very last building', 'one of the last building', 'the one after the last', 'one before the last', NULL, 'D', '"Last but one" means the penultimate — the one immediately before the very last.', 2024), 
('english', 'WAEC', 'The new shopping plaza is easy on the eye. This means that the shopping plaza is:', 'grandiose', 'cool', 'attractive', 'expensive', NULL, 'C', '"Easy on the eye" is an idiom meaning visually attractive or pleasant to look at.', 2024), 
('english', 'WAEC', 'That nonchalant attitude of Jonah''s baffles me. "Amazes" means:', 'baffles', 'irritates', 'amuses', 'shocks', NULL, 'A', '"Amazes me" is closest to "baffles me" in meaning — both suggest being surprised or confused by something.', 2024), 
('english', 'WAEC', 'A good friend is supposed to be with you through thick and thin. This means that a good friend should:', 'be prepared for any eventuality', 'stand by you in good and bad times', 'accompany you anywhere you go', 'always advise you', NULL, 'B', '"Through thick and thin" means through all circumstances, good and bad.', 2024), 
('english', 'WAEC', 'Willy has been under the weather for some days. This means that Willy has been:', 'sad', 'ill', 'in the rain', 'outside the country', NULL, 'B', '"Under the weather" is an idiom meaning feeling ill or unwell.', 2024), 
('english', 'WAEC', 'Taya was beaten at his own game. This means that:', 'Taya''s strategies were leaked', 'Taya''s missed the target', 'Taya''s forgot his own tactics', 'Taya''s methods were used to defeat him', NULL, 'D', '"Beaten at his own game" means that someone used the same tactics or strategies against you to defeat you.', 2024), 
('english', 'WAEC', 'We never believed that Father would pull through that fever. This means that we did not believe that he would:', 'recover from the sickness', 'acquire immunity to the fever', 'die from the sickness', 'suffer so long', NULL, 'A', '"Pull through" means to recover from a serious illness or difficult situation.', 2024), 
('english', 'WAEC', 'It was apparent that John damage the desk. "Apparent" means:', 'noticed', 'evident', 'recognized', 'acknowledged', NULL, 'B', '"Apparent" means clearly visible or obvious — nearest in meaning to "evident."', 2024), 
('english', 'WAEC', 'Some of the merchant''s good were impounded by the customs officers.', 'intercepted', 'delayed', 'confiscated', 'screened', NULL, 'C', '"Impounded" means officially seized or taken into custody — nearest in meaning to "confiscated."', 2024), 
('english', 'WAEC', 'My trust in Abah suddenly began to wane. "Wane" means:', 'dissipate', 'disappear', 'decrease', 'deteriorate', NULL, 'C', '"Wane" means to gradually decrease or diminish — nearest in meaning to "decrease."', 2024), 
('english', 'WAEC', 'Some believe it is ominous for the owl to perch on the roof of a house. "Ominous" means:', 'forbidden', 'portentous', 'prophetic', 'suspicious', NULL, 'B', '"Ominous" means giving the impression that something bad is going to happen — nearest in meaning to "portentous."', 2024), 
('english', 'WAEC', 'The new shopping mall is on the fringe of the town. "Fringe" means:', 'limit', 'outside', 'middle', 'edge', NULL, 'D', '"Fringe" means the outer edge or margin of an area — nearest in meaning to "edge."', 2024), 
('english', 'WAEC', 'The supervisor spurned the offer of help from the cleaner. "Spurned" means:', 'denied', 'rebuked', 'defied', 'refuted', NULL, 'A', '"Spurned" means rejected or turned down — nearest in meaning to "denied."', 2024), 
('english', 'WAEC', 'I have eventually found the book. "Eventually" means:', 'actually', 'lately', 'presently', 'finally', NULL, 'D', '"Eventually" means in the end, after a long time — nearest in meaning to "finally."', 2024), 
('english', 'WAEC', 'It is not good for a child to be unduly inquisitive. "Inquisitive" means:', 'naughty', 'playful', 'curious', 'troublesome', NULL, 'C', '"Inquisitive" means having a strong desire to know or learn things — nearest in meaning to "curious."', 2024), 
('english', 'WAEC', 'Kofi is rather audacious; he jumps off high fences. "Audacious" means:', 'daring', 'smart', 'active', 'agile', NULL, 'A', '"Audacious" means showing a willingness to take surprisingly bold risks — nearest in meaning to "daring."', 2024), 
('english', 'WAEC', 'The criminal approached the crowd menacingly. "Menacingly" means:', 'stealthily', 'cunningly', 'calculatedly', 'threateningly', NULL, 'D', '"Menacingly" means in a way that suggests danger or harm — nearest in meaning to "threateningly."', 2024), 
('english', 'WAEC', 'He said that they _________ painting the house by then.', 'will have finished', 'will finish', 'would have finished', 'would finish', NULL, 'C', 'The sentence requires the future perfect tense in reported speech — "would have finished" is correct as it indicates an action completed before a point in the past.', 2024), 
('english', 'WAEC', 'I will wear my _________ Dress to the dance.', 'blue silk new', 'new blue silk', 'silk new blue', 'silk blue new', NULL, 'B', 'The correct adjective order in English is: opinion, size, age, shape, color, origin, material, purpose. So "new blue silk" follows the correct sequence.', 2024), 
('english', 'WAEC', 'If I _________ an eagle, I would fly to distant lands.', 'was', 'were', 'am', 'be', NULL, 'B', '"Were" is used in conditional/subjunctive sentences expressing hypothetical or imaginary situations, e.g. "If I were an eagle..."', 2024), 
('english', 'WAEC', 'The teacher needs _________ to write the note on the chalkboard.', 'chalks', 'some chalk', 'chalk', 'many chalks', NULL, 'C', '"Chalk" is an uncountable noun and should not be pluralized. The correct form is simply "chalk."', 2024), 
('english', 'WAEC', 'The man said that he _________ eaten there previously.', 'had', 'ate', 'has eaten there before', 'had eaten there yesterday', NULL, 'A', 'In reported speech, the past perfect tense "had eaten" is used to show that the action occurred before the reporting time.', 2024), 
('english', 'WAEC', 'To be healthy we need to eat a _________ diet everyday.', 'balanced', 'complete', 'mixed', 'delicious', NULL, 'A', '"Balanced diet" is the standard collocation in health and nutrition — a diet that contains all the necessary nutrients in the right proportions.', 2024), 
('english', 'WAEC', 'I can rustle _________ an omelette at least.', 'out', 'up', 'in', 'off', NULL, 'B', '"Rustle up" is the correct phrasal verb meaning to prepare or make something quickly, especially food.', 2024), 
('english', 'WAEC', 'Banku was _________ unhappy after the fight.', 'very', 'too', 'much', 'such', NULL, 'A', '"Very" is the correct adverb to intensify the adjective "unhappy" in this context.', 2024), 
('english', 'WAEC', 'Everything would be _________ cheaper in the sales.', 'greatly', 'considerably', 'strongly', 'most', NULL, 'B', '"Considerably" is the appropriate adverb meaning by a large or significant amount — fits "cheaper" well.', 2024), 
('english', 'WAEC', 'The boot of my new car was _________ in the accident.', 'cracked', 'broken', 'dented', 'chipped', NULL, 'C', '"Dented" is the most appropriate word for the boot of a car being damaged — it means having a depression or hollow made by a blow.', 2024), 
('english', 'WAEC', 'Parents should create an environment _________ their children can grow.', 'which', 'what', 'from where', 'in which', NULL, 'D', '"In which" is the correct relative pronoun phrase to introduce the relative clause describing the environment.', 2024), 
('english', 'WAEC', 'In spite of his shortcomings, we admire him _________.', 'yet', 'though', 'but', 'however', NULL, 'C', '"But" is the appropriate conjunction to show contrast in this sentence.', 2024), 
('english', 'WAEC', 'Amadi''s plan _________ at the last moment.', 'fell down', 'fell off', 'fell on', 'fell through', NULL, 'D', '"Fell through" is the correct phrasal verb meaning a plan or deal failed or didn''t succeed.', 2024), 
('english', 'WAEC', 'You think I am hungry, _________?', 'am I', 'aren''t I', 'don''t you', 'I', NULL, 'C', 'The question tag should reflect the main clause subject and tense. "You think" uses "you" and "think," so the tag is "don''t you?"', 2024), 
('english', 'WAEC', 'Maria _________ tears when she was told that she had failed the final examination.', 'broke to', 'broke up', 'broke with', 'broke into', NULL, 'D', '"Broke into tears" is the correct phrasal verb expression meaning to suddenly start crying.', 2024), 
('english', 'WAEC', 'Jide _________ before I arrived.', 'could', 'must have eaten', 'can have eaten', 'had eaten', NULL, 'D', '"Had eaten" is the correct past perfect form to indicate an action that happened before another past action (before I arrived).', 2024), 
('english', 'WAEC', 'He claimed to be an expert, but he knew next to _________ about it.', 'everything', 'nothing', 'something', 'anything', NULL, 'B', '"Knew next to nothing" is the correct idiomatic expression meaning he knew almost nothing about it.', 2024), 
('english', 'WAEC', '_________ the textbooks, he advised his daughter to face her studies.', 'Having being bought', 'Having bought', 'Having been bought', 'Having buy', NULL, 'B', '"Having bought" is the correct perfect participle form — it indicates the action was completed before the main clause action.', 2024), 
('english', 'WAEC', 'Deficiency of _________ just one essential vitamin may cause illness.', 'on', 'in', 'from', 'of', NULL, 'B', '"Deficiency in" is the correct collocation — one is deficient in a nutrient or vitamin.', 2024), 
('english', 'WAEC', 'This is the _________ he has submitted his assignment since joining the class.', 'earliest', 'early', 'latest', 'soonest', NULL, 'A', '"Earliest" is the correct superlative form to indicate the first time something has happened.', 2024), 
('english', 'WAEC', 'It is wise to _________ with what one has rather than go on borrowing.', 'make up', 'make out', 'make do', 'make over', NULL, 'C', '"Make do" is the correct phrasal verb meaning to manage with what is available, even if it is not ideal.', 2024), 
('english', 'WAEC', 'The teacher was _________ hasty in meting out punishment.', 'more', 'much', 'scarcely', 'somewhat', NULL, 'D', '"Somewhat" is the appropriate adverb meaning to a moderate degree — fits "hasty" in this context.', 2024), 
('english', 'WAEC', 'Everybody should treat their parents with respect, _________?', 'should they', 'shouldn''t they', 'shouldn''t we', 'should we', NULL, 'B', '"Shouldn''t they" is the correct negative question tag for the positive statement "Everybody should treat their parents with respect."', 2024), 
('english', 'WAEC', 'The experienced clerk found herself at _________ crossroad.', 'a crossroads', 'some crossroads', 'any crossroads', 'the crossroads', NULL, 'A', '"At a crossroads" is the correct expression meaning at a point where a decision must be made.', 2024), 
('english', 'WAEC', 'We are playing _________ the problems of the company.', 'off', 'up', 'out', 'down', NULL, 'D', '"Playing down" is the correct phrasal verb meaning to minimize the importance of something.', 2024), 
('english', 'WAEC', 'You _________ have walked home alone so late at night.', 'would not', 'might not', 'ought not to', 'need not to', NULL, 'C', '"Ought not to" is the correct modal expression indicating something that was inadvisable or wrong to do.', 2024), 
('english', 'WAEC', 'Did you notice that the _________ had been removed?', 'price''s tag', 'prices tag', 'price tag', 'prices'' tag', NULL, 'C', '"Price tag" is the standard compound noun — no apostrophe is needed as it is a compound noun not a possessive.', 2024), 
('english', 'WAEC', 'It is mandatory that consumables should have _________ dates.', 'sell-by', 'sell-out', 'sell-off', 'sell-on', NULL, 'A', '"Sell-by date" is the term used for the date by which a product should be sold — the standard expression in commerce.', 2024), 
('english', 'WAEC', 'Don''t judge the boy _________ his past.', 'by', 'from', 'at', 'for', NULL, 'A', '"Judge by" is the correct collocation — "by" is the correct preposition used to indicate the criteria for judgment.', 2024);
